private final int _next() throws XMLStreamException
    {
        while (true) {
            switch (_currentState) {
                case XML_ATTRIBUTE_VALUE:
                    ++_nextAttributeIndex;
                    break;
                case XML_START_ELEMENT: 
                    if (_nextAttributeIndex >= _attributeCount){
                        _localName = _xmlReader.getLocalName();
                        _namespaceURI = _xmlReader.getNamespaceURI();
                        String text = _collectUntilTag();
                        if (!hasMoreChildrenInSameLevel()) {
                            _textValue = text;  
                            return XML_TEXT;
                        }

                        else{
                            _elementStack.push(_newElementInfo());
                            return XML_START_ELEMENT;
                        }
                    }
                    break;

                case XML_ATTRIBUTE_NAME:
                    return (_currentState = XML_ATTRIBUTE_VALUE);

                case XML_TEXT: 
                   if (!hasMoreChildrenInSameLevel() && _xmlReader.getEventType() != XMLStreamConstants.START_ELEMENT ){
                       return XML_END;
                    }

                    else if(!hasMoreChildrenInSameLevel()&&_xmlReader.getEventType()==XMLStreamConstants.START_ELEMENT){
                       _elementStack.peek()._totalElements++;
                    }
                    break;
                case XML_END:
                    return XML_END;
            }



            switch (_skipUntilTag()) {
                case XMLStreamConstants.CHARACTERS:
                    continue;
                case XMLStreamConstants.END_DOCUMENT:
                    return (_currentState = XML_END);
                case XMLStreamConstants.END_ELEMENT:
                    return _handleEndElement();
            }

            _currentState = XML_START_ELEMENT;
            break;
        }
    }

    boolean hasMoreChildrenInSameLevel(){
        for(int i = 0;i<_elementStack.size();i++){
            ElementInfo e  = _elementStack.get(_elementStack.size()-1-i);
            if((e.index+1)<e.count){
                return true;
            }
        }
        return false;
    }

